package com.example.userapp.viewmodel;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import com.example.userapp.model.User;
import com.example.userapp.repository.UserRepository;

import java.util.List;

public class UserViewModel extends ViewModel {

    private final UserRepository userRepository;
    private final MutableLiveData<List<User>> usersLiveData = new MutableLiveData<>();
    private final MutableLiveData<User> selectedUserLiveData = new MutableLiveData<>();
    private final MutableLiveData<String> errorLiveData = new MutableLiveData<>();
    private final MutableLiveData<Boolean> loadingLiveData = new MutableLiveData<>();

    public UserViewModel() {
        userRepository = new UserRepository();
    }

    public LiveData<List<User>> getUsers() {
        return usersLiveData;
    }

    public LiveData<User> getSelectedUser() {
        return selectedUserLiveData;
    }

    public LiveData<String> getError() {
        return errorLiveData;
    }

    public LiveData<Boolean> isLoading() {
        return loadingLiveData;
    }

    public void loadUsers(int page, int perPage) {
        loadingLiveData.setValue(true);
        userRepository.fetchUsers(page, perPage, new UserRepository.OnUsersLoadedCallback() {
            @Override
            public void onSuccess(List<User> users) {
                usersLiveData.postValue(users);
                loadingLiveData.postValue(false);
            }

            @Override
            public void onError(String errorMessage) {
                errorLiveData.postValue(errorMessage);
                loadingLiveData.postValue(false);
            }
        });
    }

    public void loadAllUsers() {
        loadingLiveData.setValue(true);
        userRepository.fetchAllUsers(new UserRepository.OnUsersLoadedCallback() {
            @Override
            public void onSuccess(List<User> users) {
                usersLiveData.postValue(users);
                loadingLiveData.postValue(false);
            }

            @Override
            public void onError(String errorMessage) {
                errorLiveData.postValue(errorMessage);
                loadingLiveData.postValue(false);
            }
        });
    }

    public void loadUserById(int userId) {
        loadingLiveData.setValue(true);
        userRepository.fetchUserById(userId, new UserRepository.OnUserLoadedCallback() {
            @Override
            public void onSuccess(User user) {
                selectedUserLiveData.postValue(user);
                loadingLiveData.postValue(false);
            }

            @Override
            public void onError(String errorMessage) {
                errorLiveData.postValue(errorMessage);
                loadingLiveData.postValue(false);
            }
        });
    }
}


